import bisect
class Solution:
    def maxRectangleArea(self, xCoord, yCoord):
        cols = {}
        for x, y in zip(xCoord, yCoord):
            cols.setdefault(x, []).append(y)
        for x in cols:
            cols[x].sort()
        xs_sorted = sorted(cols.keys())
        col_set = {x: set(cols[x]) for x in cols}
        best = -1
        for xi, x1 in enumerate(xs_sorted):
            ys = cols[x1]
            for i in range(len(ys) - 1):
                y_lo, y_hi = ys[i], ys[i + 1]
                for x2 in xs_sorted[xi + 1:]:
                    col2 = cols[x2]
                    lo_i = bisect.bisect_right(col2, y_lo)
                    hi_i = bisect.bisect_left(col2, y_hi)
                    if lo_i < hi_i:
                        break
                    has_lo = y_lo in col_set[x2]
                    has_hi = y_hi in col_set[x2]
                    if has_lo and has_hi:
                        area = (x2 - x1) * (y_hi - y_lo)
                        if area > best:
                            best = area
                        break
                    if has_lo or has_hi:
                        break
        return best

