var maxRectangleArea = function(xCoord, yCoord) {
    const n = xCoord.length;
    const cols = new Map();
    for (let i = 0; i < n; i++) {
        if (!cols.has(xCoord[i])) cols.set(xCoord[i], []);
        cols.get(xCoord[i]).push(yCoord[i]);
    }
    const xsSorted = Array.from(cols.keys()).sort((a, b) => a - b);
    for (const x of xsSorted) cols.get(x).sort((a, b) => a - b);
    const colSet = new Map();
    for (const x of xsSorted) colSet.set(x, new Set(cols.get(x)));
    function bisectRight(arr, val) {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo + hi) >> 1; if (arr[mid] <= val) lo = mid + 1; else hi = mid; }
        return lo;
    }
    function bisectLeft(arr, val) {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo + hi) >> 1; if (arr[mid] < val) lo = mid + 1; else hi = mid; }
        return lo;
    }
    let best = -1;
    for (let xi = 0; xi < xsSorted.length; xi++) {
        const x1 = xsSorted[xi];
        const ys = cols.get(x1);
        for (let i = 0; i + 1 < ys.length; i++) {
            const yLo = ys[i], yHi = ys[i + 1];
            for (let xj = xi + 1; xj < xsSorted.length; xj++) {
                const x2 = xsSorted[xj];
                const col2 = cols.get(x2);
                const loI = bisectRight(col2, yLo);
                const hiI = bisectLeft(col2, yHi);
                if (loI < hiI) break;
                const hasLo = colSet.get(x2).has(yLo);
                const hasHi = colSet.get(x2).has(yHi);
                if (hasLo && hasHi) {
                    const area = (x2 - x1) * (yHi - yLo);
                    if (area > best) best = area;
                    break;
                }
                if (hasLo || hasHi) break;
            }
        }
    }
    return best;
};
